exports.handler = async (event) => {
    const targetUrl = event.queryStringParameters?.url;

    if (!targetUrl) {
        return {
            statusCode: 400,
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ message: 'Missing target URL. Please provide a "url" query parameter.' }),
        };
    }

    let url;
    try {
        url = new URL(targetUrl);
    } catch (e) {
        return {
            statusCode: 400,
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ message: 'Invalid target URL format.' }),
        };
    }

    try {
        const response = await fetch(url.toString());
        const responseBody = await response.text();

        const headersToForward = {};
        response.headers.forEach((value, name) => {
            if (!['content-encoding', 'transfer-encoding', 'connection', 'keep-alive', 'proxy-authenticate', 'proxy-authorization', 'te', 'trailer', 'upgrade'].includes(name.toLowerCase())) {
                headersToForward[name] = value;
            }
        });

        return {
            statusCode: response.status,
            headers: headersToForward,
            body: responseBody,
        };

    } catch (error) {
        console.error('Error fetching target URL:', error);
        return {
            statusCode: 500,
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ message: 'Failed to fetch content from the target URL.', error: error.message }),
        };
    }
};